<template>
  <section class="section">
    <div class="section-head">
      <button class="wing-button" type="button" title="技能管理" aria-label="技能管理" @click="openManager">
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path
            d="M5.2 19.2c.7-3.7 2.7-6.7 6-9 1-.7 2.2-1.3 3.8-2 .6-.3.9-.9.8-1.5-.2-1-.8-2-1.9-3.1 3.5.7 5.8 2.9 5.8 6.2 0 1.8-.7 3.4-1.9 4.8-.4.5-1.1.6-1.7.3l-1.6-.9c-1.2 2.1-3.1 3.7-5.7 4.8-1.5.7-3 1-5.6.4z"
            fill="currentColor"
          />
          <path
            d="M8.7 16.7c.3-2 1.5-3.7 3.6-5.2-2.9.8-5 2.6-6.3 5.3 1.2.2 1.9.2 2.7-.1z"
            fill="rgba(255,255,255,0.25)"
          />
        </svg>
      </button>
    </div>

    <div class="mana-panel">
      <div class="mana-head">
        <div>
          <div class="panel-title">魔力</div>
          <div class="panel-caption">当前状态 {{ manaPercent }}% · {{ manaStateLabel }}</div>
        </div>
        <div class="mana-value">{{ store.data.渡鸦.魔力 }} / {{ store.data.渡鸦.魔力上限 }}</div>
      </div>

      <div class="mana-track">
        <div class="mana-fill" :class="manaStageClass" :style="{ width: `${manaPercent}%` }"></div>
      </div>
    </div>

    <div class="panel">
      <div class="panel-head">
        <div>
          <div class="panel-title">已掌握技能</div>
          <div class="panel-caption">点击技能查看详情</div>
        </div>
        <div class="panel-count">{{ skills.length }} 项</div>
      </div>

      <div v-if="skills.length" class="skill-list">
        <button
          v-for="skill in skills"
          :key="skill.name"
          class="skill-item"
          :class="{ active: skill.name === selectedSkillName }"
          type="button"
          @click="selectSkill(skill.name)"
        >
          <span class="skill-name">{{ skill.name }}</span>
        </button>
      </div>
      <div v-else class="empty">暂无技能</div>

      <div v-if="activeSkill" class="skill-detail">
        <div class="skill-detail-head">
          <div>
            <div class="skill-detail-title">{{ activeSkill.name }}</div>
          </div>
          <button v-if="shouldCollapseDetail" class="detail-toggle" type="button" @click="detailExpanded = !detailExpanded">
            {{ detailExpanded ? '收起' : '展开' }}
          </button>
        </div>
        <div class="skill-detail-text" :class="{ collapsed: shouldCollapseDetail && !detailExpanded }">
          {{ activeSkill.desc || '暂无技能说明。' }}
        </div>
      </div>
      <div v-else class="detail-empty">未选择技能</div>
    </div>

    <Transition name="fade">
      <div v-if="managerOpen" class="dialog-mask" @click.self="closeManager">
        <div class="dialog">
          <div class="dialog-head">
            <div class="dialog-title">渡鸦技能管理</div>
            <div class="dialog-tools">
              <button class="btn ghost" type="button" @click="resetEditor">新增技能</button>
              <button class="dialog-close" type="button" aria-label="关闭" @click="closeManager">×</button>
            </div>
          </div>

          <div class="dialog-grid">
            <div class="manager-list">
              <button
                v-for="skill in skills"
                :key="skill.name"
                class="manager-item"
                type="button"
                @click="editSkill(skill.name)"
              >
                <div class="manager-name">{{ skill.name }}</div>
                <div class="manager-desc">{{ skill.desc || '暂无说明' }}</div>
              </button>
              <div v-if="!skills.length" class="manager-empty">还没有技能，先新增一条。</div>
            </div>

            <div class="editor-panel">
              <div class="row">
                <div class="label">技能名</div>
                <div class="value">
                  <input v-model="editor.name" class="input" type="text" placeholder="例如：幻胧" />
                </div>
              </div>
              <div class="row">
                <div class="label">说明</div>
                <div class="value">
                  <textarea v-model="editor.desc" class="textarea" rows="5" placeholder="输入技能效果说明"></textarea>
                </div>
              </div>

              <div class="actions">
                <button class="btn primary" type="button" :disabled="!editor.name.trim()" @click="saveSkill">保存</button>
                <button class="btn danger" type="button" :disabled="!currentEditorKey" @click="removeSkill">删除</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </Transition>
  </section>
</template>

<script setup lang="ts">
import { getManaStageClass, getManaStateLabel } from '../manaStage';
import { useDataStore } from '../store';

const store = useDataStore();
const managerOpen = ref(false);
const detailExpanded = ref(false);
const selectedSkillName = useLocalStorage('msp_v4:status_bar:selected_skill', '');

const editor = reactive({ sourceName: '', name: '', desc: '' });

const skills = computed(() => {
  const obj = store.data.渡鸦.技能 ?? {};
  return Object.entries(obj)
    .map(([name, value]) => ({ name, desc: value?.说明 ?? '' }))
    .sort((a, b) => a.name.localeCompare(b.name, 'zh-Hans-CN'));
});

const activeSkill = computed(() => skills.value.find(skill => skill.name === selectedSkillName.value) ?? null);
const shouldCollapseDetail = computed(() => (activeSkill.value?.desc?.length ?? 0) > 90);
const manaPercent = computed(() => {
  const max = store.data.渡鸦.魔力上限;
  if (!max) {
    return 0;
  }
  return Math.round((store.data.渡鸦.魔力 / max) * 100);
});
const manaStateLabel = computed(() => getManaStateLabel(manaPercent.value));
const manaStageClass = computed(() => getManaStageClass(manaPercent.value));

const currentEditorKey = computed(() => editor.sourceName || editor.name.trim());

watchEffect(() => {
  if (!skills.value.length) {
    selectedSkillName.value = '';
    detailExpanded.value = false;
    return;
  }

  if (!selectedSkillName.value || !skills.value.some(skill => skill.name === selectedSkillName.value)) {
    selectedSkillName.value = skills.value[0].name;
  }
});

watch(activeSkill, () => {
  detailExpanded.value = false;
});

function resetEditor() {
  editor.sourceName = '';
  editor.name = '';
  editor.desc = '';
}

function selectSkill(name: string) {
  selectedSkillName.value = name;
}

function editSkill(name: string) {
  const skill = store.data.渡鸦.技能?.[name];
  editor.sourceName = name;
  editor.name = name;
  editor.desc = skill?.说明 ?? '';
}

function openManager() {
  managerOpen.value = true;
  if (activeSkill.value) {
    editSkill(activeSkill.value.name);
  } else {
    resetEditor();
  }
}

function closeManager() {
  managerOpen.value = false;
}

function saveSkill() {
  const name = editor.name.trim();
  if (!name) {
    return;
  }

  const skillMap = store.data.渡鸦.技能 as Record<string, { 说明: string }>;
  if (editor.sourceName && editor.sourceName !== name && editor.sourceName in skillMap) {
    delete skillMap[editor.sourceName];
  }

  skillMap[name] = { 说明: editor.desc.trim() };
  editor.sourceName = name;
  editor.name = name;
  selectedSkillName.value = name;
}

function removeSkill() {
  const name = currentEditorKey.value.trim();
  if (!name) {
    return;
  }

  const skillMap = store.data.渡鸦.技能 as Record<string, { 说明: string }>;
  if (name in skillMap) {
    delete skillMap[name];
    if (selectedSkillName.value === name) {
      selectedSkillName.value = '';
    }
    resetEditor();
  }
}
</script>

