<template>
  <section class="section">
    <div v-if="characters.length" class="list">
      <article v-for="item in characters" :key="item.key" class="item">
        <div class="top-row">
          <div class="identity">
            <div class="name">{{ item.displayName }}</div>
          </div>
          <div class="badges">
            <span class="badge" :class="item.transformed ? 'badge-accent' : 'badge-muted'">
              {{ item.transformed ? '已变身' : '未变身' }}
            </span>
            <span class="badge lust-badge" :class="item.lustClass">情欲 {{ item.lust }}</span>
          </div>
        </div>

        <div class="thought-box">
          <div class="label">心声</div>
          <div class="thought">{{ item.thought }}</div>
        </div>

        <div class="tags">
          <span v-for="emotion in item.emotions" :key="emotion.name" class="tag" :class="emotion.toneClass">
            <strong>{{ emotion.name }}</strong>
            <span>{{ emotion.level }}</span>
          </span>
          <span v-if="!item.emotions.length" class="tag muted">暂无感情</span>
        </div>
      </article>
    </div>
    <div v-else class="empty">暂无在场角色</div>
  </section>
</template>

<script setup lang="ts">
import { computed } from 'vue';
import { useDataStore } from '../store';

const store = useDataStore();

const EMOTION_LEVEL_WEIGHT = {
  极端: 4,
  强烈: 3,
  普通: 2,
  些许: 1,
  微弱: 0,
} as const;

function getEmotionToneClass(level: string) {
  switch (level) {
    case '微弱':
      return 'tag-faint';
    case '些许':
      return 'tag-light';
    case '普通':
      return 'tag-normal';
    case '强烈':
      return 'tag-strong';
    case '极端':
      return 'tag-extreme';
    default:
      return 'tag-faint';
  }
}

function getLustToneClass(lust: number) {
  if (lust >= 85) {
    return 'lust-overflow';
  }

  if (lust >= 65) {
    return 'lust-burning';
  }

  if (lust >= 40) {
    return 'lust-warm';
  }

  if (lust >= 15) {
    return 'lust-awake';
  }

  return 'lust-calm';
}

type EmotionLevel = keyof typeof EMOTION_LEVEL_WEIGHT;
type PresentCharacter = {
  名称: string;
  是否变身: boolean;
  感情: Record<string, EmotionLevel>;
  心声: string;
  情欲: number;
};

const characters = computed(() =>
  (Object.entries(store.data.在场角色 ?? {}) as Array<[string, PresentCharacter]>)
    .map(([key, value]) => ({
      key,
      displayName: (value.名称 || key).trim() || key,
      transformed: value.是否变身,
      lust: value.情欲,
      lustClass: getLustToneClass(value.情欲),
      thought: value.心声,
      emotions: Object.entries(value.感情 ?? {})
        .map(([name, level]) => ({
          name,
          level,
          toneClass: getEmotionToneClass(level),
          weight: EMOTION_LEVEL_WEIGHT[level] ?? -1,
        }))
        .sort((left, right) => right.weight - left.weight || left.name.localeCompare(right.name, 'zh-Hans-CN')),
    }))
    .sort((left, right) => left.displayName.localeCompare(right.displayName, 'zh-Hans-CN')),
);
</script>

